/**
 * Seed LP targets from parsed Google Sheet data.
 * Run once: node src/utils/seed-lp-targets.js
 * Idempotent: ON CONFLICT (company, full_name) DO NOTHING
 */
require('dotenv').config();
const { Pool } = require('pg');
const { v4: uuid } = require('uuid');
const path = require('path');
const fs = require('fs');

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// Load records from lp_records.json (generated by parse_lps.py)
const recordsPath = path.join(__dirname, '../../../../lp_records.json');
const records = JSON.parse(fs.readFileSync(recordsPath, 'utf-8'));

async function seed() {
  const client = await pool.connect();
  let inserted = 0;
  let skipped = 0;

  try {
    await client.query('BEGIN');

    for (const r of records) {
      const id = uuid();
      const sectors = r.sector_interest && r.sector_interest.length > 0
        ? r.sector_interest
        : null;

      // Deduplicate by company name (case-insensitive) - skip if already exists
      const existing = await client.query(
        `SELECT id FROM lp_targets WHERE LOWER(TRIM(company)) = LOWER(TRIM($1)) LIMIT 1`,
        [r.company]
      );

      if (existing.rows.length > 0) {
        skipped++;
        continue;
      }

      await client.query(
        `INSERT INTO lp_targets
         (id, full_name, email, company, fund_type,
          sector_interest, geographic_focus, outreach_status, fit_score)
         VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)`,
        [
          id,
          r.full_name || null,
          r.email || null,
          r.company,
          r.fund_type || null,
          sectors,
          r.geographic_focus || null,
          r.outreach_status || 'not_started',
          null,  // fit_score: will be set by matching engine
        ]
      );
      inserted++;
    }

    await client.query('COMMIT');
    console.log(`Seed complete: ${inserted} inserted, ${skipped} skipped (already existed)`);
  } catch (err) {
    await client.query('ROLLBACK');
    console.error('Seed failed:', err.message);
    process.exit(1);
  } finally {
    client.release();
    await pool.end();
  }
}

seed();
